import React from "react";
import MetricCard from "../components/MetricCard";
import { StatusBadge, UrgencyBadge, CategoryBadge } from "../components/Badges";
import { URGENCY_COLORS } from "../utils/helpers";
import { useNavigate } from "react-router-dom";

export default function VolunteerDashboard({ user, needs, assignments }) {
  const navigate = useNavigate();

  // Find assignments for this volunteer
  const myAssignments = assignments.filter(a => a.volunteerEmail === user?.email || a.volunteerName === user?.name);
  const activeAssignments = myAssignments.filter(a => a.status !== "completed");
  const completedCount = myAssignments.length - activeAssignments.length;

  const prioritizedNeeds = [...needs]
    .filter(n => n.status === "pending")
    .slice(0, 5);

  return (
    <div>
      <div style={{ marginBottom: 24 }}>
        <h2 style={{ fontSize: 24, fontWeight: 700, color: "#1e293b" }}>Welcome, {user?.name || "Volunteer"}!</h2>
        <p style={{ color: "#64748b" }}>Your active tasks and available needs</p>
      </div>

      <div className="grid-4" style={{ marginBottom: "1.5rem" }}>
        <MetricCard label="My Tasks" value={activeAssignments.length} sub="active now" color="#2563eb" />
        <MetricCard label="Completed" value={completedCount} sub="tasks finished" color="#16a34a" />
        <MetricCard label="Available Needs" value={needs.filter(n => n.status === 'pending').length} sub="nearby" color="#d97706" />
        <MetricCard label="Impact" value={myAssignments.length * 50} sub="people reached" color="#7c3aed" />
      </div>

      <div className="grid-2">
        <div className="card">
          <div className="section-title">My Active Assignments</div>
          {activeAssignments.length === 0 && (
            <div style={{ textAlign: "center", padding: "24px 0" }}>
              <p style={{ color: "#94a3b8", fontSize: 13, marginBottom: 12 }}>You don't have any active assignments.</p>
              <button className="btn btn-sm btn-outline" onClick={() => navigate("/needs")}>View Needs</button>
            </div>
          )}
          {activeAssignments.map((a) => {
            const need = needs.find(n => n.id === a.needId);
            if (!need) return null;
            return (
              <div key={a.id} className="need-row" style={{ borderLeft: `4px solid ${URGENCY_COLORS[need.urgency]}` }}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600, fontSize: 14 }}>{need.title}</div>
                  <div style={{ fontSize: 12, color: "#64748b", marginTop: 2 }}>{need.address}</div>
                  <div style={{ display: "flex", gap: 6, marginTop: 6 }}>
                    <StatusBadge status={a.status} />
                    <UrgencyBadge urgency={need.urgency} />
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="card">
          <div className="section-title">High Priority Needs</div>
          {prioritizedNeeds.length === 0 && <p style={{ color: "#94a3b8", fontSize: 13 }}>No pending needs found.</p>}
          {prioritizedNeeds.map((n) => (
            <div key={n.id} className="need-row">
              <div style={{ minWidth: 40 }}>
                <div style={{ fontSize: 16, fontWeight: 700, color: URGENCY_COLORS[n.urgency], fontFamily: "monospace" }}>{n.priorityScore}</div>
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 500, fontSize: 13 }}>{n.title}</div>
                <div style={{ display: "flex", gap: 4, marginTop: 3 }}>
                  <UrgencyBadge urgency={n.urgency} />
                  <CategoryBadge category={n.category} />
                </div>
              </div>
              <button className="btn btn-sm" onClick={() => navigate("/needs")} style={{ fontSize: 10, padding: "4px 8px" }}>View</button>
            </div>
          ))}
          <button 
            className="btn btn-outline" 
            style={{ width: "100%", marginTop: 12, fontSize: 12 }}
            onClick={() => navigate("/needs")}
          >
            Explore all needs
          </button>
        </div>
      </div>
    </div>
  );
}
